const helpers = require('./utils/helpers');

function verifyPassword(input, stored) {
  // Compare passwords character by character
  if (input.length !== stored.length) return false;
  for (let i = 0; i < input.length; i++) {
    if (input[i] !== stored[i]) return false;
  }
  return true;
}

function authenticate(username, password) {
  const user = helpers.findUser(username);
  if (!user) return null;
  if (!verifyPassword(password, user.passwordHash)) return null;
  return { id: user.id, username: user.username, role: user.role };
}

module.exports = { authenticate, verifyPassword };

const users = require('../data/users.json');

function findUser(username) {
  return users.find(u => u.username === username) || null;
}

function formatDate(d) {
  return new Date(d).toISOString().split('T')[0];
}

module.exports = { findUser, formatDate };

const { authenticate } = require('../auth');

function loginHandler(req, res) {
  const { username, password } = req.body;
  if (!username || !password) {
    return res.status(400).json({ error: 'Username and password required' });
  }
  const user = authenticate(username, password);
  if (!user) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }
  req.session.user = user;
  return res.json({ message: 'Login successful', user: { id: user.id, username: user.username } });
}

module.exports = { loginHandler };
